pw.test("Status Code é 200 OK", () => {
    pw.expect(pw.response.status).toBe(200);
});

pw.test("Valida contrato - Retorna mensagem e nova quantidade", () => {
    pw.expect(pw.response.body.mensagem).not.toBe(undefined);
    pw.expect(pw.response.body.novaQuantidade).not.toBe(undefined);
});

pw.test("Status Code é 400 ou 422", () => {
    const statusAceitos = [400, 422];
    const statusValido = statusAceitos.includes(pw.response.status);
    
    pw.expect(statusValido).toBe(true);
});

